module top_module(
	input [7:0] operand1,
	input [7:0] b,
	input [1:0] op,
	input clock,
	output reg [15:0] result
);always @ (posedge clock) begin
	case (op)
		2'b00: result <= operand1 + b;
		2'b01: result <= operand1 - b;
		2'b10: result <= operand1 * b;
		2'b11: result <= operand1 / b;
	endcase
end

endmodule
